import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_name -> framework -> package -> (requested, resolved)
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        lookup[name] = {}
        for fw in proj['frameworks']:
            lookup[name][fw['framework']] = {}
            for pkg in fw['topLevelPackages']:
                lookup[name][fw['framework']][pkg['id']] = (pkg['requestedVersion'], pkg['resolvedVersion'])
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

changes = []
unchanged = []

for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for fw in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        b_pkgs = b.get(proj,{}).get(fw,{})
        a_pkgs = a.get(proj,{}).get(fw,{})
        all_pkgs = sorted(set(list(b_pkgs.keys()) + list(a_pkgs.keys())))
        for pkg in all_pkgs:
            b_ver = b_pkgs.get(pkg, (None,None))
            a_ver = a_pkgs.get(pkg, (None,None))
            if b_ver[1] != a_ver[1]:
                changes.append((proj, fw, pkg, b_ver[1], a_ver[1]))
            else:
                unchanged.append((proj, fw, pkg, a_ver[1]))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]} ({c[1]}): {c[2]}  {c[3]} -> {c[4]}')
else:
    print('None')

print()
print(f'=== UNCHANGED ({len(unchanged)} entries) ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}): {u[2]}  {u[3]}')
"

